import React, { useState } from 'react';
import {
    Container,
    Paper,
    Typography,
    TextField,
    Button,
    Card,
    CardContent,
    Grid,
    Box,
} from '@mui/material';
import CalculateIcon from '@mui/icons-material/Calculate';

const MortgageCalculator = () => {
    const [formData, setFormData] = useState({
        propertyCost: 2000000,
        initialPayment: 500000,
        termYears: 20,
    });

    const [results, setResults] = useState(null);

    const calculate = () => {
        const { propertyCost, initialPayment, termYears } = formData;
        const loanAmount = propertyCost - initialPayment;
        const annualRate = 9.6;
        const monthlyRate = annualRate / 12 / 100;
        const totalPayments = termYears * 12;
        const totalRate = Math.pow(1 + monthlyRate, totalPayments);
        const monthlyPayment = loanAmount * monthlyRate * totalRate / (totalRate - 1);
        const totalPayment = monthlyPayment * totalPayments;
        const overpayment = totalPayment - loanAmount;
        const requiredIncome = monthlyPayment * 2.5;

        setResults({
            monthlyPayment: Math.round(monthlyPayment),
            totalPayment: Math.round(totalPayment),
            overpayment: Math.round(overpayment),
            requiredIncome: Math.round(requiredIncome),
            loanAmount,
        });
    };

    const formatCurrency = (amount) => {
        return new Intl.NumberFormat('ru-RU', {
            style: 'currency',
            currency: 'RUB',
            minimumFractionDigits: 0,
        }).format(amount);
    };

    return (
        <Container maxWidth="lg">
            <Paper elevation={3} sx={{ p: 4, mt: 4 }}>
                <Typography variant="h4" gutterBottom>
                    <CalculateIcon sx={{ mr: 2 }} />
                    Ипотечный калькулятор
                </Typography>

                <Grid container spacing={3}>
                    <Grid item xs={12} md={6}>
                        <TextField
                            fullWidth
                            label="Стоимость недвижимости, ₽"
                            value={formData.propertyCost}
                            onChange={(e) => setFormData({ ...formData, propertyCost: e.target.value })}
                            margin="normal"
                        />
                        <TextField
                            fullWidth
                            label="Первоначальный взнос, ₽"
                            value={formData.initialPayment}
                            onChange={(e) => setFormData({ ...formData, initialPayment: e.target.value })}
                            margin="normal"
                        />
                        <TextField
                            fullWidth
                            label="Срок кредита (лет)"
                            value={formData.termYears}
                            onChange={(e) => setFormData({ ...formData, termYears: e.target.value })}
                            margin="normal"
                        />

                        <Button
                            variant="contained"
                            size="large"
                            onClick={calculate}
                            sx={{ mt: 2 }}
                            startIcon={<CalculateIcon />}
                        >
                            Рассчитать
                        </Button>
                    </Grid>

                    <Grid item xs={12} md={6}>
                        {results && (
                            <Box>
                                <Card sx={{ mb: 2, bgcolor: 'primary.light', color: 'white' }}>
                                    <CardContent>
                                        <Typography variant="h6">Ежемесячный платеж:</Typography>
                                        <Typography variant="h4">{formatCurrency(results.monthlyPayment)}</Typography>
                                    </CardContent>
                                </Card>

                                <Card sx={{ mb: 2 }}>
                                    <CardContent>
                                        <Typography variant="body2">Общая сумма выплат:</Typography>
                                        <Typography variant="h6">{formatCurrency(results.totalPayment)}</Typography>
                                    </CardContent>
                                </Card>

                                <Card sx={{ mb: 2 }}>
                                    <CardContent>
                                        <Typography variant="body2">Необходимый доход:</Typography>
                                        <Typography variant="h6">{formatCurrency(results.requiredIncome)}</Typography>
                                        <Typography variant="caption">(платеж × 2.5)</Typography>
                                    </CardContent>
                                </Card>
                            </Box>
                        )}
                    </Grid>
                </Grid>
            </Paper>
        </Container>
    );
};

export default MortgageCalculator;
